UPDATE ROOM_TYPE
SET IS_ACTIVE = 'N'
WHERE ROOM_TYPE_ID = #{roomTypeId}

UPDATE ROOM_TYPE
SET IS_ACTIVE = 'Y'
WHERE ROOM_TYPE_ID = #{roomTypeId}

UPDATE ROOM_IMAGE
SET IMAGE_URL = #{image_url}
WHERE ROOM_TYPE_ID = #{roomTypeId}

UPDATE ROOM_TYPE
SET APPROVE_STATUS = 'PENDING'
WHERE ROOM_TYPE_ID = #{roomTypeId}

UPDATE room_type
SET approve_status = 'APPROVED'
WHERE room_type_id = #{roomTypeId}

UPDATE room_type
SET approve_status = 'REJECTED'
WHERE room_type_id = #{roomTypeId}
